// Calculate this week vs last week metrics
const items = $input.all().map(i => i.json);
const config = $('Set report config variables').first().json;
const sorted = items.sort((a, b) => new Date(b.Date || b.date) - new Date(a.Date || a.date));
const thisWeek = sorted.slice(0, 7);
const lastWeek = sorted.slice(7, 14);
function sumField(arr, field) { return arr.reduce((sum, row) => sum + (parseFloat(row[field]) || 0), 0); }
function pctChange(current, previous) { if (previous === 0) return current > 0 ? 100 : 0; return Math.round(((current - previous) / previous) * 100); }
const metrics = { thisWeek: { revenue: sumField(thisWeek, 'Revenue'), leads: sumField(thisWeek, 'Leads'), conversions: sumField(thisWeek, 'Conversions'), adSpend: sumField(thisWeek, 'Ad Spend'), supportTickets: sumField(thisWeek, 'Support Tickets') }, lastWeek: { revenue: sumField(lastWeek, 'Revenue'), leads: sumField(lastWeek, 'Leads'), conversions: sumField(lastWeek, 'Conversions'), adSpend: sumField(lastWeek, 'Ad Spend'), supportTickets: sumField(lastWeek, 'Support Tickets') } };
metrics.changes = { revenue: pctChange(metrics.thisWeek.revenue, metrics.lastWeek.revenue), leads: pctChange(metrics.thisWeek.leads, metrics.lastWeek.leads), conversions: pctChange(metrics.thisWeek.conversions, metrics.lastWeek.conversions), adSpend: pctChange(metrics.thisWeek.adSpend, metrics.lastWeek.adSpend), supportTickets: pctChange(metrics.thisWeek.supportTickets, metrics.lastWeek.supportTickets) };
metrics.thisWeek.conversionRate = metrics.thisWeek.leads > 0 ? Math.round((metrics.thisWeek.conversions / metrics.thisWeek.leads) * 100) : 0;
metrics.thisWeek.roas = metrics.thisWeek.adSpend > 0 ? Math.round((metrics.thisWeek.revenue / metrics.thisWeek.adSpend) * 100) / 100 : 0;
return [{ json: { metrics, rawDataPoints: sorted.length, companyName: config.companyName, slackChannel: config.slackChannel, emailRecipients: config.emailRecipients, reportDate: new Date().toISOString().split('T')[0] } }];

// Format the AI digest for Slack and email
const aiResponse = $input.first().json;
const prev = $('Calculate weekly comparisons').first().json;
const digest = aiResponse.message?.content || aiResponse.text || aiResponse.content || 'Report generation failed.';
const slackMessage = ':bar_chart: *Weekly Performance Digest — ' + prev.reportDate + '*\n\n' + digest;
const emailHtml = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;"><h2>Weekly Performance Digest — ' + prev.reportDate + '</h2><div style="background: #f5f5f5; padding: 20px; border-radius: 8px; margin: 20px 0;"><h3>Key Metrics</h3><p>Revenue: $' + prev.metrics.thisWeek.revenue + ' (' + (prev.metrics.changes.revenue > 0 ? '+' : '') + prev.metrics.changes.revenue + '%)<br>Leads: ' + prev.metrics.thisWeek.leads + '<br>Conversions: ' + prev.metrics.thisWeek.conversions + '<br>ROAS: ' + prev.metrics.thisWeek.roas + 'x</p></div><div style="white-space: pre-wrap;">' + digest + '</div></div>';
return [{ json: { slackMessage, emailHtml, emailSubject: 'Weekly Performance Digest — ' + prev.reportDate, slackChannel: prev.slackChannel, emailRecipients: prev.emailRecipients, reportDate: prev.reportDate } }];
